# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    role = str(user.get("role", "basic")).lower()
    discount_map = {
        "enterprise": 0.30,
        "premium": 0.15,
        "basic": 0.0,
    }
    if role not in discount_map:
        raise ValueError("Invalid user role")

    total = 0.0
    for item in cart_items:
        if isinstance(item, dict):
            price = float(item.get("price", 0))
            quantity = int(item.get("quantity", 1))
        else:
            price = float(item[0])
            quantity = int(item[1]) if len(item) > 1 else 1
        total += price * quantity

    discount_pct = discount_map[role]
    discounted_total = total * (1 - discount_pct)

    if not isinstance(payment_details, dict):
        raise ValueError("Invalid payment details")

    if not payment_details.get("method"):
        raise ValueError("Missing payment method")

    payment_result = {
        "status": "success",
        "charged_amount": round(discounted_total, 2),
        "original_amount": round(total, 2),
        "discount_percentage": int(discount_pct * 100),
        "role": role,
        "payment_method": payment_details.get("method"),
    }
    return payment_result